// src/components/ListaAgendamentos.jsx
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const baseURL = process.env.REACT_APP_API_URL;

const STATUS_LABELS = {
  'Novo': 'Novo',
  'Retorno': 'Retorno',
  'Solicitado': 'Solicitado',
};
const STATUS_COLORS = {
  'Novo': "bg-[#2FA74E] text-white",
  'Retorno': "bg-[#FEC139] text-[#555555]",
  'Solicitado': "bg-[#DA3648] text-white",
};


export default function ListaAgendamentos({ onEditar, reloadKey }) {
  const [agendamentos, setAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  const [busca, setBusca] = useState('');
  const [filtroData, setFiltroData] = useState('');
  const [filtroHora, setFiltroHora] = useState('');

  const navigate = useNavigate();

  useEffect(() => {
    setCarregando(true);

    // Recupera token e role do localStorage (ou de onde você armazenou após login)
    const token = localStorage.getItem('token');
    const role  = localStorage.getItem('role'); // ex: "aluno" ou "recepcao"

    // Escolhe a URL de listagem conforme o role:
    // - recepcao → lista todos (/api/agendamentos)
    // - aluno    → lista apenas os próprios (/api/agendamentos/meus)
    const url = role === 'recepcao'
      ? '/api/agendamentos'
      : '/api/agendamentos/meus';



    axios.get(url, {
      headers: { Authorization: `Bearer ${token}` }
    })
      .then((res) => {
        setAgendamentos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar agendamentos:', err);
        setCarregando(false);
      });
  }, [reloadKey]);


  // Função para filtrar a lista localmente (por texto, data, hora)
  const filtrarAgendamentos = (lista) => {
    return lista.filter(ag => {
      const textoBusca = busca.toLowerCase();
      const campos = [
        ag.operadorNome,
        ag.auxiliarNome,
        ag.disciplinaNome,
        ag.pacienteNome,
        ag.telefone,
        ag.status
      ].map(x => x ? x.toLowerCase() : '');
      const matchTexto = campos.some(campo => campo.includes(textoBusca));
      const matchData = filtroData ? (ag.data && ag.data.startsWith(filtroData)) : true;
      const matchHora = filtroHora ? (ag.hora && ag.hora.startsWith(filtroHora)) : true;
      return matchTexto && matchData && matchHora;
    });
  };

  const agendamentosFiltrados = filtrarAgendamentos(agendamentos).slice(0, 100);
  const disciplinaNome = agendamentosFiltrados[0]?.disciplinaNome || '';
  //const dataAtual = agendamentosFiltrados[0]?.data
   // ? agendamentosFiltrados[0].data.slice(0, 10).split('-').reverse().join('/')
  //  : '';
  //const semestre = ""; // se for relevante, preencha aqui

  const handleImprimir = () => {
    const disciplinaAtual = agendamentosFiltrados[0]?.disciplinaId || null;
    const filtros = {
      data: filtroData,
      hora: filtroHora,
      busca: busca
    };

    navigate('/print-agendamentos', {
      state: {
        disciplinaId: disciplinaAtual,
        disciplinaNome,
        filtros
      }
    });
  };

  const handleDeletar = (id) => {
    if (!window.confirm('Tem certeza que deseja deletar este agendamento?')) {
      return;
    }
    const token = localStorage.getItem('token');
    axios.delete(`/api/agendamentos/${id}`, {
      headers: { Authorization: `Bearer ${token}` }
    })
      .then(() => {
        setAgendamentos(prev => prev.filter(a => a.id !== id));
      })
      .catch((err) => {
        console.error('Erro ao deletar agendamento:', err.response?.data || err.message);
        alert('Não foi possível deletar o agendamento.');
      });
  };

  if (carregando) return <p>Carregando agendamentos...</p>;
  if (agendamentos.length === 0) return <p>Nenhum agendamento cadastrado.</p>;

  return (
    <div className="mx-auto py-2 px-4">
      {/* Título da lista */}
      <h2 className="text-xl font-semibold mb-4">Lista de Agendamentos</h2>

      <div className="bg-white rounded-2xl">
        {/* Filtros e ações */}
        <div className="flex flex-col md:flex-row md:items-end gap-3 p-4 pt-2 pb-2 bg-white mb-2">
          <input
            type="text"
            placeholder="Pesquisar..."
            value={busca}
            onChange={e => setBusca(e.target.value)}
            className="flex-1 border rounded px-4 py-2"
          />
          <div className="flex items-center gap-4">
            <input type="date" value={filtroData} onChange={e => setFiltroData(e.target.value)} className="border p-2 rounded" />
            <input type="time" value={filtroHora} onChange={e => setFiltroHora(e.target.value)} className="border p-2 rounded" />
            <button onClick={handleImprimir} className="px-4 py-2 bg-blue-100 text-blue-800 rounded-lg hover:bg-blue-200">
              Imprimir
            </button>
          </div>
        </div>

        {/* Cabeçalho desktop */}
        <div className="hidden md:grid grid-cols-9 gap-x-4 px-5 py-2 bg-gray-100 rounded-t-xl font-semibold text-gray-600 mb-2">
          <span>Operador</span>
          <span>Auxiliar</span>
          <span>Disciplina</span>
          <span>Paciente</span>
          <span>Telefone</span>
          <span>Data</span>
          <span>Hora</span>
          <span>Incluído em</span>
          <span className="text-right">Ações</span>
        </div>

        {/* Lista de cards */}
        <div className="space-y-3">
          {agendamentosFiltrados.map(ag => (
            <div key={ag.id} className="relative flex flex-col md:grid md:grid-cols-9 gap-1 bg-gray-50 rounded-xl px-4 py-2 shadow-sm hover:bg-gray-100 transition">
              {/* menu três pontos */}
              <button
                onClick={() => setMenuOpenId(menuOpenId === ag.id ? null : ag.id)}
                className="absolute top-2 right-2 p-1 text-gray-500 hover:text-gray-700"
              >
                ⋮
              </button>

              {/* mobile labels */}
              <div className="md:hidden w-full mb-1"><strong>Operador:</strong> {ag.operadorNome || '-'}</div>
              <div className="md:hidden w-full mb-1"><strong>Auxiliar:</strong> {ag.auxiliarNome || '-'}</div>
              <div className="md:hidden w-full mb-1"><strong>Disciplina:</strong> {ag.disciplinaNome || '-'}</div>
              <div className="md:hidden w-full mb-1"><strong>Paciente:</strong> {ag.pacienteNome || '-'}</div>
              <div className="md:hidden w-full mb-1"><strong>Telefone:</strong> {ag.telefone || '-'}</div>
              <div className="md:hidden w-full mb-1"><strong>Data:</strong> {ag.data ? ag.data.split('T')[0].split('-').reverse().join('/') : '-'}</div>
              <div className="md:hidden w-full mb-1"><strong>Hora:</strong> {ag.hora || '-'}</div>
              <div className="md:hidden w-full mb-1"><strong>Incluído em:</strong> {formatDateTime(ag.createdAt)}</div>

              {/* menu actions */}
              {menuOpenId === ag.id && (
                <div className="absolute top-8 right-2 bg-white border rounded shadow-md flex flex-col z-10">
                  <button onClick={() => { onEditar(ag); setMenuOpenId(null); }} className="px-4 py-2 hover:bg-gray-100 text-left">Editar</button>
                  <button onClick={() => { handleDeletar(ag.id); setMenuOpenId(null); }} className="px-4 py-2 hover:bg-gray-100 text-left">Deletar</button>
                </div>
              )}

              {/* desktop cells */}
              <div className="hidden md:block truncate">{ag.operadorNome || '-'}</div>
              <div className="hidden md:block truncate">{ag.auxiliarNome || '-'}</div>
              <div className="hidden md:block truncate">{ag.disciplinaNome || '-'}</div>
              <div className="hidden md:block truncate">{ag.pacienteNome || '-'}</div>
              <div className="hidden md:block truncate">{ag.telefone || '-'}</div>
              <div className="hidden md:block truncate">{ag.data ? ag.data.split('T')[0].split('-').reverse().join('/') : '-'}</div>
              <div className="hidden md:block truncate">{ag.hora || '-'}</div>
              <div className="hidden md:block truncate">{formatDateTime(ag.createdAt)}</div>
              <div className="hidden md:flex justify-end">  {/* placeholder for actions header */}
                {/* ações via menu */}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
